import React, { useState, useEffect } from 'react';
import styles from '../Styles/Components/ObservacoesTurno.module.css';

const ObservacoesTurno = () => {
  const [texto, setTexto] = useState("");

  // 1. Resolve o F5: Busca o texto salvo ao carregar a página
  useEffect(() => {
    const salvo = localStorage.getItem('observacoesSolver');
    if (salvo) {
      setTexto(salvo);
    }
  }, []);

  // 2. Salva automaticamente a cada alteração
  const handleChange = (e) => {
    const novoTexto = e.target.value;
    setTexto(novoTexto);
    localStorage.setItem('observacoesSolver', novoTexto);
  };

  return (
    <div className={styles.container}>
      <h2 className={styles.titulo}>Observações para o próximo turno</h2>
      <textarea
        className={styles.textarea}
        value={texto}
        onChange={handleChange}
        placeholder="Digite aqui as sobras, avarias, pendências de packing, distribuição e chamados..."
      />
    </div>
  );
};

export default ObservacoesTurno;
